		return {
			status: response.status,
			contentType,
			classification: classifyStatus(response.status),
			objectKeys,
			runnerWorkflowRunId,
		};
	} catch (error) {
		return {
			status: null,
			contentType: null,
			classification: "network-error",
			objectKeys: null,
			runnerWorkflowRunId: null,
			error: summarizeNetworkError(error),
		};
	} finally {
		clearTimeout(timeout);
	}
}

